"use strict";(self.webpackChunkarduino_edukit_algerie=self.webpackChunkarduino_edukit_algerie||[]).push([[9075],{5696:(e,n,r)=>{r.r(n),r.d(n,{assets:()=>s,contentTitle:()=>l,default:()=>u,frontMatter:()=>o,metadata:()=>i,toc:()=>c});const i=JSON.parse('{"id":"projet-serrure/code","title":"Code Arduino \u2014 Serrure Intelligente","description":"Lance ce code simple pour lire l\'UID de ta carte RFID et noter-le :","source":"@site/docs/projet-serrure/code.md","sourceDirName":"projet-serrure","slug":"/projet-serrure/code","permalink":"/projets_ecoles/docs/projet-serrure/code","draft":false,"unlisted":false,"editUrl":"https://github.com/arduino-edu-algerie/arduino-edukit/tree/main/docs/projet-serrure/code.md","tags":[],"version":"current","lastUpdatedBy":"jodokfehlmann","lastUpdatedAt":1776593215000,"frontMatter":{"id":"code","title":"Code Arduino \u2014 Serrure Intelligente","sidebar_label":"\ud83d\udcbb Code"},"sidebar":"tutorialSidebar","previous":{"title":"\ud83d\udd0c C\xe2blage","permalink":"/projets_ecoles/docs/projet-serrure/cablage"},"next":{"title":"\ud83d\udcdd Exercices","permalink":"/projets_ecoles/docs/projet-serrure/exercices"}}');var t=r(4848),d=r(8453);const o={id:"code",title:"Code Arduino \u2014 Serrure Intelligente",sidebar_label:"\ud83d\udcbb Code"},l="\ud83d\udcbb Code Arduino \u2014 Serrure Intelligente",s={},c=[];function a(e){const n={a:"a",admonition:"admonition",code:"code",h1:"h1",header:"header",p:"p",pre:"pre",strong:"strong",...(0,d.R)(),...e.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(n.header,{children:(0,t.jsx)(n.h1,{id:"-code-arduino--serrure-intelligente",children:"\ud83d\udcbb Code Arduino \u2014 Serrure Intelligente"})}),"\n",(0,t.jsx)(n.pre,{children:(0,t.jsx)(n.code,{className:"language-cpp",metastring:'title="serrure_intelligente.ino"',children:"// ============================================\n// Arduino EduKit Alg\xe9rie \u2014 Serrure Intelligente RFID\n// Version 1.0 \u2014 Licence MIT\n// ============================================\n\n#include <SPI.h>\n#include <MFRC522.h>\n#include <Keypad.h>\n#include <LiquidCrystal_I2C.h>\n#include <Servo.h>\n#include <EEPROM.h>\n\n// === BROCHES ===\n#define RST_PIN     9\n#define SS_PIN      10\n#define SERVO_PIN   1\n#define BUZZER      A1\n#define LED_VERTE   A2\n#define LED_ROUGE   A3\n\n// === PARAM\xc8TRES ===\n#define CODE_PIN        \"1234\"    // Code PIN par d\xe9faut \u2014 CHANGE-LE !\n#define DUREE_OUVERTURE 3000      // Temps d'ouverture en ms\n#define MAX_TENTATIVES  3         // Tentatives avant alarme\n#define SERVO_FERME     0         // Angle verrou ferm\xe9\n#define SERVO_OUVERT    90        // Angle verrou ouvert\n\n// === CLAVIER ===\nconst byte LIGNES = 4, COLONNES = 4;\nchar touches[LIGNES][COLONNES] = {\n  {'1','2','3','A'},\n  {'4','5','6','B'},\n  {'7','8','9','C'},\n  {'*','0','#','D'}\n};\nbyte bocheLignes[LIGNES]   = {2, 3, 4, 5};\nbyte brocheColonnes[COLONNES] = {6, 7, 8, A0};\n\n// === OBJETS ===\nMFRC522 rfid(SS_PIN, RST_PIN);\nLiquidCrystal_I2C lcd(0x27, 16, 2);\nKeypad clavier = Keypad(makeKeymap(touches), bocheLignes, brocheColonnes, LIGNES, COLONNES);\nServo servo;\n\n// === VARIABLES ===\nint tentatives = 0;\nString saisie = \"\";\nbool enAttenteSaisie = false;\n\n// ============================================\n// FONCTIONS\n// ============================================\n\nvoid ouvrir() {\n  servo.write(SERVO_OUVERT);\n  digitalWrite(LED_VERTE, HIGH);\n  tone(BUZZER, 1000, 200);\n  lcd.clear();\n  lcd.setCursor(0, 0); lcd.print(\"  ACCES ACCORDE \");\n  lcd.setCursor(0, 1); lcd.print(\"   Bienvenue !  \");\n  delay(DUREE_OUVERTURE);\n  fermer();\n}\n\nvoid fermer() {\n  servo.write(SERVO_FERME);\n  digitalWrite(LED_VERTE, LOW);\n  tentatives = 0;\n  afficherAccueil();\n}\n\nvoid refuser() {\n  tentatives++;\n  digitalWrite(LED_ROUGE, HIGH);\n  tone(BUZZER, 300, 500);\n  lcd.clear();\n  lcd.setCursor(0, 0); lcd.print(\"  ACCES REFUSE  \");\n  lcd.setCursor(0, 1);\n  lcd.print(\"Tentatives: \");\n  lcd.print(tentatives);\n  lcd.print(\"/\"); lcd.print(MAX_TENTATIVES);\n  delay(1500);\n  digitalWrite(LED_ROUGE, LOW);\n\n  if (tentatives >= MAX_TENTATIVES) {\n    declencherAlarme();\n  } else {\n    afficherAccueil();\n  }\n}\n\nvoid declencherAlarme() {\n  lcd.clear();\n  lcd.setCursor(0, 0); lcd.print(\"!!! ALARME !!!  \");\n  lcd.setCursor(0, 1); lcd.print(\"Trop de tentativ\");\n  for (int i = 0; i < 10; i++) {\n    tone(BUZZER, 2000, 200);\n    digitalWrite(LED_ROUGE, HIGH);\n    delay(300);\n    digitalWrite(LED_ROUGE, LOW);\n    delay(200);\n  }\n  tentatives = 0;\n  afficherAccueil();\n}\n\nvoid afficherAccueil() {\n  lcd.clear();\n  lcd.setCursor(0, 0); lcd.print(\" Serrure EduKit \");\n  lcd.setCursor(0, 1); lcd.print(\"Carte ou # code \");\n  saisie = \"\";\n  enAttenteSaisie = false;\n}\n\nbool verifierCarteRFID(String uid) {\n  // Lire les UIDs autoris\xe9s depuis l'EEPROM\n  // (simplifi\xe9 : un seul UID stock\xe9 en dur pour l'exemple)\n  return uid == \"A1B2C3D4\";  // Remplace par l'UID de ta carte !\n}\n\nbool verifierCode(String code) {\n  return code == CODE_PIN;\n}\n\n// ============================================\n// SETUP & LOOP\n// ============================================\n\nvoid setup() {\n  Serial.begin(9600);\n  SPI.begin();\n  rfid.PCD_Init();\n\n  lcd.init();\n  lcd.backlight();\n\n  servo.attach(SERVO_PIN);\n  servo.write(SERVO_FERME);\n\n  pinMode(BUZZER, OUTPUT);\n  pinMode(LED_VERTE, OUTPUT);\n  pinMode(LED_ROUGE, OUTPUT);\n\n  afficherAccueil();\n  Serial.println(\"=== Serrure EduKit pr\xeate ===\");\n}\n\nvoid loop() {\n  // V\xe9rifier une carte RFID\n  if (rfid.PICC_IsNewCardPresent() && rfid.PICC_ReadCardSerial()) {\n    String uid = \"\";\n    for (byte i = 0; i < rfid.uid.size; i++) {\n      uid += String(rfid.uid.uidByte[i], HEX);\n    }\n    uid.toUpperCase();\n    Serial.print(\"Carte d\xe9tect\xe9e: \"); Serial.println(uid);\n\n    if (verifierCarteRFID(uid)) {\n      ouvrir();\n    } else {\n      refuser();\n    }\n    rfid.PICC_HaltA();\n    return;\n  }\n\n  // V\xe9rifier le clavier\n  char touche = clavier.getKey();\n  if (touche) {\n    if (touche == '#') {\n      // Touche # : valider le code\n      if (verifierCode(saisie)) {\n        ouvrir();\n      } else {\n        refuser();\n      }\n      saisie = \"\";\n    } else if (touche == '*') {\n      // Touche * : effacer\n      saisie = \"\";\n      lcd.setCursor(0, 1); lcd.print(\"Code effac\xe9     \");\n      delay(500);\n      afficherAccueil();\n    } else {\n      // Chiffre : ajouter \xe0 la saisie\n      saisie += touche;\n      lcd.setCursor(0, 1);\n      for (int i = 0; i < saisie.length(); i++) {\n        lcd.print(\"*\");  // Masquer le code\n      }\n    }\n  }\n}\n"})}),"\n",(0,t.jsxs)(n.admonition,{title:"Trouver l'UID de ta carte",type:"tip",children:[(0,t.jsx)(n.p,{children:"Lance ce code simple pour lire l'UID de ta carte RFID et noter-le :"}),(0,t.jsx)(n.pre,{children:(0,t.jsx)(n.code,{className:"language-cpp",children:'// Dans loop(), apr\xe8s rfid.PICC_ReadCardSerial() :\nSerial.print("UID: ");\nfor (byte i = 0; i < rfid.uid.size; i++) {\n  Serial.print(rfid.uid.uidByte[i], HEX); Serial.print(" ");\n}\nSerial.println();\n'})})]}),"\n",(0,t.jsxs)(n.p,{children:["\u2705 ",(0,t.jsx)(n.strong,{children:"Code charg\xe9 !"})," \u2192 Passe aux ",(0,t.jsx)(n.strong,{children:(0,t.jsx)(n.a,{href:"./exercices",children:"exercices \u2192"})})]})]})}function u(e={}){const{wrapper:n}={...(0,d.R)(),...e.components};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(a,{...e})}):a(e)}},8453:(e,n,r)=>{r.d(n,{R:()=>o,x:()=>l});var i=r(6540);const t={},d=i.createContext(t);function o(e){const n=i.useContext(d);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function l(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(t):e.components||t:o(e.components),i.createElement(d.Provider,{value:n},e.children)}}}]);